+        "SELECT instance_id FROM atc_leader_lease WHERE lease_slot = 1",
+        &[],
+    )
+    .await
+    {
+        Outcome::Ok(r) => r,
+        Outcome::Err(e) => {
+            return Outcome::Err(DbError::Internal(format!("leader_lease renew select: {e}")));
+        }
+        Outcome::Cancelled(r) => return Outcome::Cancelled(r),
